class CryptoWallet {
    private var privateKey: Data?
    private var publicKey: Data?
    
    init() {
        generateKeyPair()
    }
    
    func generateKeyPair() {
        let keyPair = P256.KeyPair()
        self.privateKey = keyPair.privateKey.rawRepresentation
        self.publicKey = keyPair.publicKey.rawRepresentation
    }
    
    func signTransaction(transaction: String) -> Data? {
        guard let privateKey = self.privateKey else { return nil }
        
        let message = transaction.data(using: .utf8)!
        let signature = try? P256.Signing.PrivateKey(rawRepresentation: privateKey)
        let signedData = try? signature?.sign(message)
        
        return signedData?.rawRepresentation
    }
    
    func getPublicKey() -> String {
        return publicKey?.hexString ?? ""
    }
    
    func getPrivateKey() -> String {
        return privateKey?.hexString ?? ""
    }
}

extension Data {
    var hexString: String {
        return map { String(format: "%02hhx", $0) }.joined()
    }
}

class BlockchainClient {
    private let baseURL = "https://api.blockchain.com/v3/exchange"
    
    func sendTransaction(transaction: String, signature: String, publicKey: String) async throws -> String {
        guard let url = URL(string: "\(baseURL)/tx") else {
            throw URLError(.badURL)
        }
        
        var request = URLRequest(url: url)
        request.httpMethod = "POST"
        request.setValue("application/json", forHTTPHeaderField: "Content-Type")
        
        let body = [
            "transaction": transaction,
            "signature": signature,
            "publicKey": publicKey
        ]
        
        request.httpBody = try JSONSerialization.data(withJSONObject: body)
        
        let (data, response) = try await URLSession.shared.data(for: request)
        
        guard let httpResponse = response as? HTTPURLResponse,
              (200...299).contains(httpResponse.statusCode) else {
            throw URLError(.badServerResponse)
        }
        
        return String(data: data, encoding: .utf8) ?? ""
    }
    
    func getBalance(address: String) async throws -> Double {
        guard let url = URL(string: "\(baseURL)/balance/\(address)") else {
            throw URLError(.badURL)
        }
        
        let (data, response) = try await URLSession.shared.data(for: URLRequest(url: url))
        
        guard let httpResponse = response as? HTTPURLResponse,
              (200...299).contains(httpResponse.statusCode) else {
            throw URLError(.badServerResponse)
        }
        
        let json = try JSONSerialization.jsonObject(with: data) as? [String: Any]
        return json?["balance"] as? Double ?? 0.0
    }
}

